import React, { useEffect, useState } from 'react'
import {
    Card, Row, Col, Button,
    Space, Modal, message,
    Table, Input, Tag
} from 'antd';

import {
    PlusOutlined,
    EyeOutlined,
    EditOutlined,
    DeleteOutlined
} from '@ant-design/icons';
import hasAuthObject from '../../helpers/hasAuthObject';
import Api from '../../helpers/api';
import handleApiError from '../../helpers/handleApiError';
import timeStampsFormat from '../../helpers/dateFormat';

const api = new Api;

// setup auth object config for this page
const authobjectCfg = {
    view: 'stock-opname-view', //button display detail
    create: 'stock-opname-create', //button add
    update: 'stock-opname-update', //button edit, 
    delete: 'stock-opname-delete', //button delete
}

const List = (props) => {

    const [selectedRowKeys, setSelectedRowKeys] = useState([])
    const [selectedRecord, setSelectedRecord] = useState([])
    const [q, setQ] = useState('')
    const [loading, setLoading] = useState(false)
    const [data, setData] = useState([])
    const [pagination, setPagination] = useState({})

    useEffect(() => {
        fetch()
    }, [q])

    const fetch = (params = {}) => {
        // console.log('params:', params);
        setLoading(true)

        api.getStockOpnameList({ ...params, q })
            .then(response => {
                const data = response.data;

                let pagination = {}

                pagination.current = data.current_page
                pagination.total = data.total;
                pagination.pageSize = parseInt(data.per_page);

                setData(data.data)
                setPagination(pagination)
                setLoading(false)
            })
            .catch(error => {
                setLoading(false)
                handleApiError(error, props)
            })

    }

    const handleTableChange = (paginate, filters, sorter) => {

        const pager = { ...pagination };
        pager.current = paginate.current;

        setPagination(pager)

        fetch({
            per_page: paginate.pageSize,
            page: paginate.current,
            sort_field: sorter.field,
            sort_order: sorter.order === 'ascend' ? 'asc' : 'desc',
            // ...filters,
        });
    }

    const handleEdit = () => {
        if (selectedRowKeys.length > 1) {
            Modal.warning({
                title: `Anda memilih ${selectedRowKeys.length} data, silahkan hanya pilih 1 data`,
            });
        } else if (selectedRecord[0].status == 2) { //approved
            Modal.warning({
                title: `Stock opname approved cannot be edited`,
            });
        } else if (selectedRecord[0].status == 3) { //rejected
            Modal.warning({
                title: `Stock opname rejected cannot be edited`,
            });
        } else {
            props.history.push(`/stock-opname/edit/${selectedRowKeys[0]}`)
        }
    }

    const handleView = () => {
        if (selectedRowKeys.length > 1) {
            Modal.warning({
                title: `Anda memilih ${selectedRowKeys.length} data, silahkan hanya pilih 1 data`,
            });
        } else {
            props.history.push(`/stock-opname/view/${selectedRowKeys[0]}`)
        }
    }

    const handleDelete = () => {
        Modal.confirm({
            title: `Delete ${selectedRowKeys.length} data?`,
            okText: 'Yes',
            okType: 'danger',
            cancelText: 'No',
            onOk: () => {
                massDeleteData()
            },
            onCancel: () => {
                console.log('Cancel');
            },
        });
    }

    const massDeleteData = () => {
        api.massDeleteStockOpname({ id: selectedRowKeys })
            .then(response => {
                // console.log(response.data)
                message.success('Delete data success');
                fetch();
                setSelectedRowKeys([])
            })
            .catch(error => {
                //console.log(error.response)
                message.error('Failed to delete');
                handleApiError(error, props)
            });
    }

    //on check table item
    const onSelectChange = (selectedRowKeys, record) => {
        setSelectedRowKeys(selectedRowKeys)
        setSelectedRecord(record)
    }

    const rowSelection = {
        selectedRowKeys,
        onChange: onSelectChange,
        // type: 'radio'
    };

    const searchData = (value) => {
        setQ(value);
    }

    const hasSelected = selectedRowKeys.length > 0;

    const columns = [
        {
            title: 'Status',
            dataIndex: 'status',
            sorter: true,
            className: 'col-center',
            render: (status) => {
                switch (status) {
                    case 0:
                        return (<Tag color="#fe8b00">Draft</Tag>)
                    case 1:
                        return (<Tag color="#87d068">Waiting Approve</Tag>)
                    case 2:
                        return (<Tag color="#108ee9">Approved</Tag>)
                    case 3:
                        return (<Tag color="#fe0000">Rejected</Tag>)
                    default:
                        return null
                }
            },
            width: 150
        },
        {
            title: 'Code',
            dataIndex: 'code',
            sorter: true,
        },
        {
            title: 'Plant',
            dataIndex: 'room',
            render: (room) => {
                if (room && room.plant) return room.plant.name
            },
        },
        {
            title: 'Room',
            dataIndex: 'room',
            render: (room) => {
                if (room) return room.name
            },
        },
        {
            title: 'Created at',
            dataIndex: 'created_at',
            sorter: true,
            render: (created_at) => {
                if (created_at) return timeStampsFormat(created_at)
            },
        },
        {
            title: 'Created by',
            dataIndex: 'created_by',
            render: (created_by) => {
                if (created_by) return created_by.fullname
            },
        },
        {
            title: 'Note',
            dataIndex: 'note',
            render: (note, record) => {
                return `${record.remark ? record.remark : ''} ${note ? note : ''}`
            },
        },
    ]

    return (
        <Card>
            <Space direction="vertical" size="large" style={{ width: '100%' }}>
                <Row>
                    <Col lg={19}>
                        <Space>
                            {hasAuthObject(authobjectCfg.create) &&
                                <Button
                                    type="primary"
                                    onClick={() => { props.history.push('/stock-opname/add') }}
                                    icon={<PlusOutlined />}
                                >Add</Button>
                            }

                            {hasAuthObject(authobjectCfg.update) &&
                                <Button
                                    onClick={() => handleEdit()}
                                    disabled={!hasSelected}
                                    icon={<EditOutlined />}
                                >Edit</Button>
                            }

                            {hasAuthObject(authobjectCfg.view) &&
                                <Button
                                    onClick={() => handleView()}
                                    disabled={!hasSelected}
                                    icon={<EyeOutlined />}
                                >View</Button>
                            }

                            {hasAuthObject(authobjectCfg.delete) &&
                                <Button
                                    danger
                                    onClick={() => handleDelete()}
                                    disabled={!hasSelected}
                                    icon={<DeleteOutlined />}
                                >Delete</Button>
                            }
                        </Space>
                    </Col>
                    <Col md={5} >
                        <Input.Search placeholder="Search"
                            onSearch={searchData} />
                    </Col>
                </Row>
                <Row>
                    <Col lg={24} xs={24}>
                        <Table
                            loading={loading}
                            rowSelection={hasAuthObject(authobjectCfg.view || authobjectCfg.update || authobjectCfg.delete) ? rowSelection : null}
                            columns={columns}
                            rowKey={record => record.id}
                            onChange={handleTableChange}
                            dataSource={data}
                            pagination={{
                                pageSizeOptions: ['20', '50', '100', '200'],
                                showSizeChanger: true,
                                showQuickJumper: true,
                                showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} items`,
                                ...pagination
                            }}
                            scroll={{ y: 300, x: 1000 }} />
                    </Col>
                </Row>
            </Space>
        </Card>
    )
}

export default List